using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Tipo de missão (Etapa 5.1) — escolha obrigatória ao criar uma missão. Só
/// existem estes três tipos:
///
/// - <see cref="Principal"/>: missão de progressão principal de um mundo. Ao
///   ser concluída, liberta a área do Boss desse mundo no Mapa-Múndi — para
///   isso, esta MissionData deve estar referenciada em
///   <see cref="WorldData.mainMission"/> (ver WorldMapController.CheckBossUnlocks).
/// - <see cref="Secundaria"/>: missão extra, opcional, espalhada pelo mundo,
///   com recompensa específica (itens/recursos/upgrades) ao ser concluída.
/// - <see cref="Quest"/>: missão menor, pedida por um NPC (recados/favores),
///   normalmente mais curta e local.
/// </summary>
public enum MissionType
{
    Principal,
    Secundaria,
    Quest
}

/// <summary>
/// Uma tarefa de uma <see cref="MissionData"/> (Sistema de Missões — apenas dois
/// níveis: Missão e Tarefa, sem "passos"). As tarefas de uma missão NÃO são
/// necessariamente uma lista linear: cada tarefa fica "activa" (disponível para
/// ser concluída e visível no Diário) quando TODAS as tarefas listadas em
/// <see cref="dependsOnTaskIds"/> já estiverem concluídas — em qualquer ordem
/// entre si. Tarefas sem dependências ficam activas desde o início da missão,
/// pelo que podem existir VÁRIAS tarefas activas em simultâneo (ex: "interagir
/// com X" e "interagir com Y", em qualquer ordem, ambas necessárias para
/// desbloquear uma terceira tarefa "falar com Z").
///
/// O estado "concluída" de cada tarefa é guardado por <c>MissionManager</c> numa
/// variável global BOOL própria (<see cref="MissionData.TaskCompletedVariable"/>),
/// marcada por Action_CompleteMissionTask/Action_SetMissionTaskState em qualquer
/// evento de NPC ou de objecto (recolher item, etc.) — ou automaticamente, se
/// <see cref="autoCompleteConditions"/> estiver preenchido (ver abaixo). Quando
/// TODAS as tarefas da missão ficam concluídas, a missão é concluída
/// automaticamente.
///
/// No Diário, cada tarefa "visível" (concluída OU activa) aparece numa lista com
/// um ícone de "Check" para as já concluídas — ver DiarySectionUI.RefreshTasks.
/// Tarefas ainda bloqueadas (dependências não cumpridas) não aparecem.
/// </summary>
[System.Serializable]
public class MissionTask
{
    [Tooltip("Identificador único desta tarefa DENTRO da missão (ex: \"falar_pescador\", \"recolher_sementes\") — usado em \"Depends On Task Ids\" de outras tarefas desta missão, por Action_CompleteMissionTask/Action_SetMissionTaskState/Condition_MissionTaskState e para guardar o estado \"concluída\" desta tarefa. Vazio = é gerado automaticamente como \"tarefa_<índice>\" (0 = primeira) — mas dá um nome próprio a qualquer tarefa que vá ser referenciada por outra (em \"Depends On Task Ids\") ou por uma Acção/Condição de NPC, para não quebrar se a ordem da lista mudar.")]
    public string taskId;

    [Tooltip("Texto mostrado no Diário (lista de tarefas) enquanto esta tarefa estiver activa ou já tiver sido concluída (ex: \"Encontrar os 3 troncos perdidos\", \"Recolher 5 Sementes\").")]
    [TextArea]
    public string description;

    [Header("Pré-requisitos (tarefas não-lineares)")]
    [Tooltip("\"Task Id\" de outras tarefas DESTA missão que têm de estar TODAS concluídas (em qualquer ordem entre si) para esta tarefa ficar activa/disponível no Diário e poder ser concluída. Vazio = esta tarefa fica activa desde o início da missão (sem pré-requisitos). Ex: uma tarefa \"falar com o chefe\" pode ter \"Depends On Task Ids\" = [\"interagir_x\", \"interagir_y\"] — só fica activa depois das duas estarem concluídas, em qualquer ordem.")]
    public List<string> dependsOnTaskIds = new List<string>();

    [Header("Conclusão Automática (opcional)")]
    [Tooltip("Condições (reutiliza o catálogo de Condições de NPC) que, quando cumpridas E esta tarefa estiver activa, concluem-na automaticamente — sem precisar de Action_CompleteMissionTask. Útil para tarefas tipo \"Recolhe X Sementes\"/\"Tens o item Y\": a tarefa fica com \"Check\" no Diário assim que a condição passar a verdadeira, mesmo sem falar com nenhum NPC. Vazio = a tarefa só é concluída por uma Acção explícita num evento de NPC/objecto.")]
    [SerializeReference] public List<NpcCondition> autoCompleteConditions = new List<NpcCondition>();

    [Tooltip("Se activo (padrão), TODAS as \"Auto Complete Conditions\" têm de se cumprir; se inactivo, basta UMA.")]
    public bool autoCompleteRequireAll = true;
}

/// <summary>
/// Uma "Pista" guardada no Diário, dentro da secção da missão a que pertence
/// (Sistema de Pistas/Rumores). Criada por Action_ShowFullscreenImage quando
/// "saveAsClue" está activo — a imagem/título/descrição ficam disponíveis para
/// reabrir em ecrã inteiro a partir do Diário (DiarySectionUI), mesmo depois de
/// a cena onde foi mostrada ter terminado. O estado "obtido" é persistido por
/// PlayerProgress.obtainedClueIds (apenas o ID; estes dados — imagem/texto —
/// vivem sempre neste ScriptableObject).
/// </summary>
[System.Serializable]
public class MissionClue
{
    [Tooltip("Identificador único desta pista dentro da missão (usado por Action_ShowFullscreenImage/Condition_HasClue e para persistência no save).")]
    public string clueId;

    [Tooltip("Título mostrado no Diário (opcional).")]
    public string title;

    [TextArea]
    [Tooltip("Descrição/texto mostrado junto à imagem (opcional).")]
    public string description;

    [Tooltip("Imagem mostrada em ecrã inteiro (FullscreenImageUI) e na lista de Pistas do Diário.")]
    public Sprite image;
}

/// <summary>
/// Define uma missão (Etapa 5.1). Não guarda estado próprio: o estado vive em
/// duas variáveis globais bool do GameVariables (gerenciador único e flexível,
/// reutilizado tal como está) — uma de activação ("missão iniciada") e uma de
/// conclusão. Lidas/escritas por MissionManager
/// (StartMission/CompleteMission/IsMissionStarted/IsMissionCompleted) e
/// reutilizáveis directamente em qualquer Condition_BoolVariable /
/// Action_SetBoolVariable, condições de drops (Etapa 4.3) e desactivação de
/// inimigos (Etapa 5.4).
/// </summary>
[CreateAssetMenu(menuName = "Animals/Mission Data", fileName = "NewMission")]
public class MissionData : ScriptableObject
{
    [Header("Identidade")]
    [Tooltip("Identificador único da missão (também usado para derivar os nomes das variáveis, se vazios).")]
    public string missionId;

    public string displayName;

    [TextArea] public string description;

    [Tooltip("Tipo da missão — escolha obrigatória. 'Principal': progressão principal do mundo, liberta a área do Boss ao ser concluída (precisa estar referenciada em WorldData.mainMission). 'Secundaria': missão extra/opcional com recompensa específica. 'Quest': missão menor pedida por um NPC (recado/favor).")]
    public MissionType missionType = MissionType.Quest;

    [Header("Variável Global de Activação")]
    [Tooltip("Nome da variável global bool que marca a missão como iniciada. Vazio = usa \"Missao_<missionId>_Iniciada\".")]
    public string startedVariableName = "";

    [Tooltip("Valor que a variável de activação assume quando a missão é iniciada (e valor esperado por IsMissionStarted).")]
    public bool startedValue = true;

    [Header("Variável Global de Conclusão")]
    [Tooltip("Nome da variável global bool que marca a missão como concluída. Vazio = usa \"Missao_<missionId>_Concluida\".")]
    public string completedVariableName = "";

    [Tooltip("Valor que a variável de conclusão assume quando a missão é concluída (e valor esperado por IsMissionCompleted).")]
    public bool completedValue = true;

    [Header("Tarefas")]
    [Tooltip("Tarefas desta missão (apenas Missão > Tarefa, sem \"passos\"). NÃO precisam de ser uma sequência linear: cada tarefa só fica activa quando as suas \"Depends On Task Ids\" estiverem todas concluídas (vazio = activa desde o início). Pode haver várias tarefas activas em simultâneo. Quando TODAS as tarefas ficam concluídas, a missão é automaticamente marcada como concluída. Pode ficar vazia para missões \"interruptor\" (sem tarefas, apenas iniciada/concluída).")]
    public List<MissionTask> tasks = new List<MissionTask>();

    [Header("Conclusão")]
    [Tooltip("Texto mostrado no banner ao concluir a missão. Vazio = usa o texto genérico \"MISSÃO CONCLUÍDA\".")]
    public string completionMessage = "";

    [Tooltip("Música/sting tocado ao concluir a missão (opcional — se vazio, toca apenas o som de UI padrão do banner, se configurado).")]
    public AudioClip completionMusic;

    [Header("Diário — Menu de Pausa (Tarefa #8)")]
    [Tooltip("Quem pediu esta missão e onde (ex: \"Nilo, Riacho dos Castores\"). Mostrado como \"Quem pediu: ...\".")]
    public string requestedBy;

    [Tooltip("O que é preciso fazer, em linguagem narrativa (ex: \"Encontrar a madeira levada pela corrente.\"). Mostrado como \"O que ele precisa: ...\".")]
    [TextArea]
    public string whatIsNeeded;

    [Tooltip("Última pista ouvida — citação exacta de um NPC, tal como foi dita (ex: \"Vi o tronco seguir na direcção das ruínas antigas.\"). Mostrado como \"Última pista: \\\"...\\\"\".")]
    [TextArea]
    public string lastHint;

    [Tooltip("Mundo onde a Íris sugere procurar (\"Região sugerida\") — memória narrativa, NÃO uma localização precisa nem um marcador no mapa. Usado também para agrupar as missões no Diário.")]
    public WorldData suggestedWorld;

    [Tooltip("Se activo, a missão aparece no Diário com o marcador \"○\" mesmo antes de ser iniciada (rumor/conversa ouvida). Se inactivo, só aparece depois de IsMissionStarted.")]
    public bool showInJournalBeforeStart = false;

    [Header("Pistas (Diário — Sistema de Pistas/Rumores)")]
    [Tooltip("Pistas (fotografias/descrições) desta missão, mostradas na sub-secção \"Pistas\" do Diário depois de obtidas (Action_ShowFullscreenImage com 'saveAsClue'). Cada uma precisa de um \"clueId\" único dentro desta missão.")]
    public List<MissionClue> clues = new List<MissionClue>();

    /// <summary>Devolve a pista com este "clueId" (ou null se não existir).</summary>
    public MissionClue GetClue(string clueId)
    {
        if (string.IsNullOrEmpty(clueId) || clues == null) return null;

        foreach (var clue in clues)
            if (clue != null && clue.clueId == clueId) return clue;

        return null;
    }

    /// <summary>Nome efectivo da variável de activação (derivado de missionId se "startedVariableName" estiver vazio).</summary>
    public string StartedVariable => !string.IsNullOrEmpty(startedVariableName) ? startedVariableName : $"Missao_{missionId}_Iniciada";

    /// <summary>Nome efectivo da variável de conclusão (derivado de missionId se "completedVariableName" estiver vazio).</summary>
    public string CompletedVariable => !string.IsNullOrEmpty(completedVariableName) ? completedVariableName : $"Missao_{missionId}_Concluida";

    /// <summary>"Task Id" efectivo de "task" — o valor de <see cref="MissionTask.taskId"/>, ou "tarefa_&lt;índice&gt;" (posição em <see cref="tasks"/>) se estiver vazio. Devolve null se "task" for null ou não pertencer a "tasks".</summary>
    public string EffectiveTaskId(MissionTask task)
    {
        if (task == null || tasks == null) return null;

        if (!string.IsNullOrEmpty(task.taskId)) return task.taskId;

        int index = tasks.IndexOf(task);
        return index >= 0 ? $"tarefa_{index}" : null;
    }

    /// <summary>Devolve a tarefa cujo "Task Id" efectivo (ver <see cref="EffectiveTaskId"/>) é "taskId" (ou null se não existir).</summary>
    public MissionTask FindTask(string taskId)
    {
        if (string.IsNullOrEmpty(taskId) || tasks == null) return null;

        for (int i = 0; i < tasks.Count; i++)
        {
            var task = tasks[i];
            if (task == null) continue;

            string id = !string.IsNullOrEmpty(task.taskId) ? task.taskId : $"tarefa_{i}";
            if (id == taskId) return task;
        }

        return null;
    }

    /// <summary>Nome da variável global BOOL que guarda se "task" está concluída ("Missao_&lt;missionId&gt;_Tarefa_&lt;taskId&gt;_Concluida"). Devolve null se "task" for inválida.</summary>
    public string TaskCompletedVariable(MissionTask task)
    {
        string taskId = EffectiveTaskId(task);
        return taskId != null ? $"Missao_{missionId}_Tarefa_{taskId}_Concluida" : null;
    }
}
